import random, math

def check_function(f, trials=100000):
    for _ in range(trials):
        x = random.uniform(0.001, 100)
        y = random.uniform(0.001, 100)
        try:
            fx = f(x)
            fy = f(y)
        except:
            return False, ("eval error", x, y)
        lhs = math.sqrt((x*x + fy*fy)/2)
        mid = (fx + y)/2
        rhs = math.sqrt(x * fy)
        if not (lhs >= mid - 1e-12 and mid >= rhs - 1e-12):
            return False, (x, y, lhs, mid, rhs)
    return True, None

for c in [0, 0.1, 0.5, 1, 2, 5, 10]:
    ok, info = check_function(lambda x, c=c: x + c, 20000)
    print(f"f(x)=x+{c}: {ok}", "" if ok else info[:4])

# Also test f(x) = x + c with c negative? Must keep f>0, so x > -c.
# Let's test c = -0.1, but restrict x > 0.1, y > 0.1
for c in [-0.1, -0.5]:
    def fneg(x, c=c):
        if x <= -c:
            return None # should not happen
        return x + c
    ok = True
    for _ in range(20000):
        x = random.uniform(max(0.001, -c+0.001), 100)
        y = random.uniform(max(0.001, -c+0.001), 100)
        fx = fneg(x)
        fy = fneg(y)
        lhs = math.sqrt((x*x + fy*fy)/2)
        mid = (fx + y)/2
        rhs = math.sqrt(x * fy)
        if not (lhs >= mid - 1e-12 and mid >= rhs - 1e-12):
            ok = False
            info = (x, y, lhs, mid, rhs)
            break
    print(f"f(x)=x+{c} (restricted): {ok}", "" if ok else info)
