import numpy as np

def sup_L(x, c, f):
    # find sup over y of 2*sqrt(x*f(y)) - y
    # we can scan y
    ys = np.logspace(-3, 3, 100000)
    vals = 2*np.sqrt(x*f(ys)) - ys
    return np.max(vals)

def inf_U(x, c, f):
    ys = np.logspace(-3, 3, 100000)
    vals = np.sqrt(2*x*x + 2*f(ys)**2) - ys
    return np.min(vals)

def f_c(c):
    return lambda y: y + c

for c in [0, 0.5, 1, 2]:
    print(f"\nc={c}:")
    for x in [0.1, 0.5, 1, 2, 5, 10]:
        f = f_c(c)
        sl = sup_L(x, c, f)
        iu = inf_U(x, c, f)
        print(f"  x={x:.1f}: sup L = {sl:.6f}, inf U = {iu:.6f}, f(x)={x+c:.6f}")
