import random, math

def violates(g, x, y):
    a = g(x)
    b = g(y)
    lhs = abs(a - b) * (a + b + 2*x + 2*y)
    rhs = (x - y - b)**2
    return lhs > rhs + 1e-12

def find_violation(g, trials=200000):
    for _ in range(trials):
        x = random.uniform(0.001, 10)
        y = random.uniform(0.001, 10)
        if violates(g, x, y):
            return x, y
    return None

# Test g = 0 on (0,1], c on (1, oo)
for c in [0.2, 0.5, 1, 2]:
    def g(x, c=c):
        if x <= 1:
            return 0.0
        else:
            return c
    v = find_violation(g)
    print(f"c={c}: {'violation' if v else 'no violation found'}", v if v else "")

# Also test a step at different threshold
for t in [0.5, 2, 5]:
    def g(x, t=t, c=1):
        if x <= t:
            return 0.0
        else:
            return c
    v = find_violation(g)
    print(f"t={t}, c=1: {'violation' if v else 'no violation found'}", v if v else "")
